glsl_code.visual:
out vec4 fragColor;
uniform float uLevel;
uniform float uScale;
uniform vec3  uColorLo;
uniform vec3  uColorHi;
void main(){
    vec2 uv = vUV.st;
    // Spectrum texture in input 0: x = frequency band, .r = magnitude.
    float band = clamp(uv.x, 0.0, 1.0);
    float mag = texture(sTD2DInputs[0], vec2(band, 0.5)).r * 20.0;
    // Radial bloom whose size pumps with the overall energy uniform.
    vec2 p = (uv - 0.5) * vec2(1.777, 1.0) * 2.0 / max(uScale, 0.0001);
    float r = length(p);
    float ring = smoothstep(0.02, 0.0, abs(r - (0.2 + uLevel * 0.6)));
    float bars = step(uv.y, clamp(mag, 0.0, 1.0));
    vec3 col = mix(uColorLo, uColorHi, clamp(mag, 0.0, 1.0)) * bars;
    col += uColorHi * ring * (0.3 + uLevel);
    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}
